class Solution:
    def countMatchingSubarrays(self, nums, pattern):
        n, m = len(nums), len(pattern)
        cmp = []
        for i in range(n-1):
            if nums[i+1] > nums[i]: cmp.append(1)
            elif nums[i+1] == nums[i]: cmp.append(0)
            else: cmp.append(-1)
        count = 0
        for i in range(len(cmp) - m + 1):
            if cmp[i:i+m] == pattern:
                count += 1
        return count

