class Solution:
    def countMatchingSubarrays(self, nums, pattern):
        n, m = len(nums), len(pattern)
        cmp = []
        for i in range(n-1):
            if nums[i+1] > nums[i]: cmp.append(1)
            elif nums[i+1] == nums[i]: cmp.append(0)
            else: cmp.append(-1)
        # KMP failure function on pattern
        fail = [0] * m
        j = 0
        for i in range(1, m):
            while j and pattern[i] != pattern[j]: j = fail[j-1]
            if pattern[i] == pattern[j]: j += 1
            fail[i] = j
        count = j2 = 0
        for c in cmp:
            while j2 and c != pattern[j2]: j2 = fail[j2-1]
            if c == pattern[j2]: j2 += 1
            if j2 == m:
                count += 1
                j2 = fail[j2-1]
        return count

