var countMatchingSubarrays = function(nums, pattern) {
    const n = nums.length, m = pattern.length;
    const cmp = [];
    for (let i = 0; i < n-1; i++) {
        if (nums[i+1] > nums[i]) cmp.push(1);
        else if (nums[i+1] === nums[i]) cmp.push(0);
        else cmp.push(-1);
    }
    const fail = new Int32Array(m);
    let j = 0;
    for (let i = 1; i < m; i++) {
        while (j && pattern[i] !== pattern[j]) j = fail[j-1];
        if (pattern[i] === pattern[j]) j++;
        fail[i] = j;
    }
    let count = 0; j = 0;
    for (const c of cmp) {
        while (j && c !== pattern[j]) j = fail[j-1];
        if (c === pattern[j]) j++;
        if (j === m) { count++; j = fail[j-1]; }
    }
    return count;
};
